import { readFileSync, writeFileSync } from "node:fs";
import { basename, dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const out = resolve(here, "neon-pilot.sql");

const files = [
  "00-bootstrap.sql",
  "01-drop-and-create-tables.sql",
  "01b-customize-schema.sql",
  "02-create-functions.sql",
  "02b-customize-functions.sql",
  "03-create-views.sql",
  "03b-customize-views.sql",
  "04-create-policies.sql",
  "04b-customize-policies.sql",
  "05-insert-data.sql",
  "05b-customize-data.sql",
];

const header = `-- ============================================================================
-- BeaconHaus Neon Pilot SQL Bundle
-- ============================================================================
-- Generated by postgres/build-neon-bundle.mjs from the ERB-derived SQL files.
-- Convenience artifact only. Do not edit this file by hand.
-- Do not include 99-fk-constraints.sql for the current pilot.
-- ============================================================================
`;

const body = files
  .map((file) => {
    const path = resolve(here, file);
    return [
      "",
      "-- ==========================================================================",
      `-- ${basename(file)}`,
      "-- ==========================================================================",
      readFileSync(path, "utf8").trim(),
      "",
    ].join("\n");
  })
  .join("\n");

writeFileSync(out, `${header}\n${body}`, "utf8");
console.log(`Wrote ${out}`);
